// ── Tooltip System ──
(function(){
  let tipEl=null;
  function getTipEl(){
    if(!tipEl){
      tipEl=document.createElement('div');
      tipEl.className='tip-box';
      document.body.appendChild(tipEl);
    }
    return tipEl;
  }
  function positionTip(anchor,tip){
    const r=anchor.getBoundingClientRect();
    const vw=window.innerWidth,vh=window.innerHeight;
    let top=r.bottom+8,left=r.left+r.width/2;
    tip.style.cssText='position:fixed!important;z-index:100000!important;display:block!important;opacity:1!important;pointer-events:auto!important;';
    tip.style.setProperty('display','block','important');
    /* measure after making visible */
    const tw=tip.offsetWidth||240,th=tip.offsetHeight||60;
    /* flip above if no room below */
    if(top+th>vh-16) top=r.top-th-8;
    /* center horizontally, clamp to viewport */
    left=Math.max(12,Math.min(left-tw/2,vw-tw-12));
    if(top<8) top=8;
    tip.style.top=top+'px';
    tip.style.left=left+'px';
    tip.classList.add('tip-visible');
  }
  function showTip(btn){
    const tip=getTipEl();
    tip.innerHTML=btn.getAttribute('data-tip')||'';
    positionTip(btn,tip);
  }
  function hideTip(){
    const tip=getTipEl();
    tip.classList.remove('tip-visible');
    tip.style.cssText='';
    tip.style.setProperty('display','none','important');
  }
  /* Delegate events on tip-btn elements */
  document.addEventListener('mouseenter',function(e){
    if(e.target.classList&&e.target.classList.contains('tip-btn'))showTip(e.target);
  },true);
  document.addEventListener('mouseleave',function(e){
    if(e.target.classList&&e.target.classList.contains('tip-btn'))hideTip();
  },true);
  document.addEventListener('focusin',function(e){
    if(e.target.classList&&e.target.classList.contains('tip-btn'))showTip(e.target);
  });
  document.addEventListener('focusout',function(e){
    if(e.target.classList&&e.target.classList.contains('tip-btn'))hideTip();
  });
  /* Touch: toggle on tap */
  document.addEventListener('click',function(e){
    if(e.target.classList&&e.target.classList.contains('tip-btn')){
      const tip=getTipEl();
      if(tip.classList.contains('tip-visible')){hideTip();}else{showTip(e.target);}
      e.stopPropagation();
    } else {
      hideTip();
    }
  });
  window._showTip=showTip;
  window._hideTip=hideTip;
})();

// ── FAQ Interactive ──
let _faqLoaded = false;
async function loadFaqContent(){
  if(_faqLoaded) return;
  const container=document.getElementById('faq-container');
  if(!container) return;
  try{
    const r=await fetch('/static/data/content.json',{cache:'force-cache'});
    if(!r.ok) throw new Error('HTTP '+r.status);
    const data=await r.json();
    const esc=s=>String(s).replace(/[&<>"]/g,c=>({'&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;'}[c]));
    const ICONS={
      phone:'<svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round" style="display:inline;vertical-align:-2px;margin-right:6px;opacity:.7"><rect x="5" y="2" width="14" height="20" rx="2"/><line x1="12" y1="18" x2="12" y2="18.01"/></svg>',
      cards:'<svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round" style="display:inline;vertical-align:-2px;margin-right:6px;opacity:.7"><rect x="3" y="1" width="13" height="19" rx="2"/><rect x="8" y="4" width="13" height="19" rx="2"/></svg>'
    };
    let html='';
    for(const cat of (data.faq||[])){
      html+='<div class="faq-cat" onclick="toggleFaqCat(this)">';
      html+='<span class="faq-cat-title">'+(ICONS[cat.icon]||'')+esc(cat.title)+'</span>';
      html+='<span class="faq-chevron">▼</span></div>';
      html+='<div class="faq-cat-items">';
      for(const it of (cat.items||[])){
        html+='<div class="faq-item" onclick="toggleFaqItem(this)">';
        html+='<span class="faq-item-title">'+esc(it.q)+'</span>';
        html+='<span class="faq-chevron">▼</span></div>';
        html+='<div class="faq-answer"><div class="faq-answer-inner">'+it.a+'</div></div>';
      }
      html+='</div>';
    }
    container.innerHTML=html;
    _faqLoaded=true;
  }catch(e){
    container.innerHTML='<p style="padding:20px;opacity:.7">Erro ao carregar conteúdo. Tente novamente.</p>';
  }
}
function toggleFAQ(){
  const sheet=document.getElementById('faq-sheet');
  const overlay=document.getElementById('faq-overlay');
  const isOpen=sheet.classList.contains('faq-open');
  if(isOpen){
    sheet.classList.remove('faq-open');
    overlay.style.display='none';
    document.body.style.overflow='';
  } else {
    loadFaqContent();
    sheet.classList.add('faq-open');
    overlay.style.display='block';
    document.body.style.overflow='hidden';
  }
}
function toggleFaqCat(el){
  const items=el.nextElementSibling;
  el.classList.toggle('faq-expanded');
  if(el.classList.contains('faq-expanded')){
    items.style.display='block';
    setTimeout(()=>{el.scrollIntoView({behavior:'smooth',block:'start'});},50);
  } else {
    items.style.display='none';
    items.querySelectorAll('.faq-item-open').forEach(i=>{
      i.classList.remove('faq-item-open');
      i.nextElementSibling.style.display='none';
    });
  }
}
function toggleFaqItem(el){
  const answer=el.nextElementSibling;
  const wasOpen=el.classList.contains('faq-item-open');
  /* Fecha todos os itens abertos na mesma categoria */
  el.parentElement.querySelectorAll('.faq-item-open').forEach(i=>{
    i.classList.remove('faq-item-open');
    i.nextElementSibling.style.display='none';
  });
  if(!wasOpen){
    el.classList.add('faq-item-open');
    answer.style.display='block';
    /* Scroll para o item aberto dentro do FAQ sheet */
    setTimeout(()=>{el.scrollIntoView({behavior:'smooth',block:'start'});},50);
  }
}
document.addEventListener('keydown',e=>{if(e.key==='Escape'){const s=document.getElementById('faq-sheet');if(s.classList.contains('faq-open'))toggleFAQ();}});
